import React, { Component } from 'react';
import {
  View,
  Text,
  FlatList,
  TextInput,
  TouchableOpacity,
  ActivityIndicator,
  StyleSheet,
} from 'react-native';
import Header from '../components/Header';
import { formatDateFull, getUserName } from '../utils/format';

export default class SearchScreen extends Component {
  constructor(props) {
    super(props);
    this.state = {
      query: '',
      results: [],
      loading: false,
      searched: false,
    };
  }

  async doSearch() {
    var { slack } = this.props;
    var { query } = this.state;
    if (!query.trim()) return;

    this.setState({ loading: true, searched: true });
    try {
      var res = await slack.searchMessages(query.trim());
      var matches = res.messages && res.messages.matches ? res.messages.matches : [];
      this.setState({ results: matches, loading: false });
    } catch (err) {
      this.setState({ results: [], loading: false });
    }
  }

  renderItem(item) {
    var { usersMap, onSelectMessage } = this.props;
    var userName = getUserName(item.user || item.username, usersMap);
    var channelName = item.channel && item.channel.name ? '#' + item.channel.name : '';

    return (
      <TouchableOpacity
        style={styles.item}
        onPress={function () { onSelectMessage && onSelectMessage(item); }}
      >
        <View style={styles.itemHeader}>
          <Text style={styles.itemUser}>{userName}</Text>
          <Text style={styles.itemChannel}>{channelName}</Text>
        </View>
        <Text style={styles.itemText} numberOfLines={3}>{item.text}</Text>
        <Text style={styles.itemTime}>{formatDateFull(item.ts)}</Text>
      </TouchableOpacity>
    );
  }

  render() {
    var { onBack } = this.props;
    var { query, results, loading, searched } = this.state;
    var self = this;

    return (
      <View style={styles.container}>
        <Header title="Search" onBack={onBack} />
        <View style={styles.searchRow}>
          <TextInput
            style={styles.input}
            placeholder="Search messages..."
            placeholderTextColor="#555577"
            value={query}
            onChangeText={function (t) { self.setState({ query: t }); }}
            onSubmitEditing={function () { self.doSearch(); }}
            returnKeyType="search"
            autoCorrect={false}
            autoFocus={true}
          />
          <TouchableOpacity
            style={styles.searchBtn}
            onPress={function () { self.doSearch(); }}
          >
            <Text style={styles.searchBtnText}>Go</Text>
          </TouchableOpacity>
        </View>

        {loading ? (
          <View style={styles.center}>
            <ActivityIndicator size="large" color="#4A90D9" />
          </View>
        ) : (
          <FlatList
            data={results}
            keyExtractor={function (item, i) { return item.ts + '_' + i; }}
            renderItem={function (obj) { return self.renderItem(obj.item); }}
            ListEmptyComponent={
              searched ? (
                <View style={styles.center}>
                  <Text style={styles.emptyText}>No results</Text>
                </View>
              ) : null
            }
          />
        )}
      </View>
    );
  }
}

var styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#1a1a2e',
  },
  searchRow: {
    flexDirection: 'row',
    padding: 8,
    borderBottomWidth: StyleSheet.hairlineWidth,
    borderBottomColor: '#2a2a4e',
  },
  input: {
    flex: 1,
    backgroundColor: '#16213e',
    color: '#ffffff',
    fontSize: 14,
    paddingHorizontal: 12,
    paddingVertical: 8,
    borderRadius: 6,
    borderWidth: 1,
    borderColor: '#2a2a4e',
    marginRight: 8,
  },
  searchBtn: {
    backgroundColor: '#4A90D9',
    paddingHorizontal: 16,
    paddingVertical: 8,
    borderRadius: 6,
    justifyContent: 'center',
  },
  searchBtnText: {
    color: '#ffffff',
    fontSize: 14,
    fontWeight: 'bold',
  },
  center: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    padding: 40,
  },
  emptyText: {
    color: '#666688',
    fontSize: 14,
  },
  item: {
    paddingHorizontal: 14,
    paddingVertical: 10,
    borderBottomWidth: StyleSheet.hairlineWidth,
    borderBottomColor: '#1a2338',
  },
  itemHeader: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    marginBottom: 4,
  },
  itemUser: {
    color: '#ccccdd',
    fontSize: 13,
    fontWeight: 'bold',
  },
  itemChannel: {
    color: '#4A90D9',
    fontSize: 11,
  },
  itemText: {
    color: '#ddddee',
    fontSize: 13,
    lineHeight: 18,
  },
  itemTime: {
    color: '#555577',
    fontSize: 10,
    marginTop: 4,
  },
});
